package com.aliucord.plugins

import android.content.Context
import com.aliucord.Http
import com.aliucord.annotations.AliucordPlugin
import com.aliucord.api.CommandsAPI.CommandResult
import com.aliucord.entities.Plugin
import java.util.HashMap

@AliucordPlugin
class AvatarSwitcher : Plugin() {

    // Paste your casual avatar base64 string here (keep the quotes!)
    private val avatar1 = ""
    // Paste your debate avatar base64 string here (keep the quotes!)
    private val avatar2 = ""

    override fun start(context: Context) {
        commands.registerCommand("avs", "Switch between your two avatars") { 
            
            // Read from settings so it remembers across app restarts
            val isAvatar1 = settings.getBool("is_avatar_1", true)
            val newAvatar = if (isAvatar1) avatar2 else avatar1
            val avatarName = if (isAvatar1) "Debate Mode" else "Casual Mode"

            try {
                // Aliucord's native request automatically handles your auth token!
                val body = HashMap<String, String>()
                body["avatar"] = newAvatar

                val req = Http.Request.newDiscordRequest("/users/@me", "PATCH")
                req.executeWithJson(body)

                // Save the new state for next time
                settings.setBool("is_avatar_1", !isAvatar1)
                
                CommandResult("Successfully switched to $avatarName!", null, false)
            } catch (e: Exception) {
                logger.error("AvatarSwitcher Error", e)
                CommandResult("Failed to switch! You are likely on a 10-minute cooldown.", null, false)
            }
        }
    }

    override fun stop(context: Context) {
        commands.unregisterAll()
    }
}
